5	/**
6	 * Applies forward-only numbered SQL migration files from migrationsDir to the
7	 * writer connection.
8	 *
9	 * Conventions:
10	 *   - File names must match /^\d{4}_.*\.sql$/ (e.g. 0001_core_tables.sql).
11	 *   - Files are applied in ascending numeric version order (not lexicographic).
12	 *   - Already-applied versions (present in schema_migrations) are skipped.
13	 *   - Each migration is wrapped in a transaction; the version is recorded in
14	 *     schema_migrations on success. If the SQL fails the transaction rolls back
15	 *     and the error propagates to the caller.
16	 *
17	 * Guards:
18	 *   - Throws if schema_migrations contains a version higher than the highest
19	 *     known migration file (forward-only guard, RC-3).
20	 *   - Throws if a migration file has a version lower than the highest
21	 *     already-applied version and is not itself applied (regression guard, AC-3).
22	 *
23	 * schema_migrations must already exist when this is called — bootstrapped by
24	 * openDbPool before migrations run.
25	 *
26	 * @throws {Error} if migrationsDir cannot be read, a SQL file cannot be read,
27	 *                 a migration SQL statement fails, or a version regression is
28	 *                 detected.
29	 */
30	export function applyMigrations(
31	  writer: Database.Database,
32	  migrationsDir: string,
33	): void {
34	  const files = fs
35	    .readdirSync(migrationsDir)
36	    .filter((f) => /^\d{4}_.*\.sql$/.test(f))
37	    .sort((a, b) => parseInt(a.slice(0, 4), 10) - parseInt(b.slice(0, 4), 10));
38	
39	  const fileVersions = files.map((f) => parseInt(f.slice(0, 4), 10));
40	  const maxFileVersion = fileVersions.reduce((max, v) => Math.max(max, v), 0);
41	
42	  // Highest version recorded in schema_migrations (0 if table is empty).
43	  const maxRow = writer
44	    .prepare('SELECT COALESCE(MAX(version), 0) AS maxv FROM schema_migrations')
45	    .get() as { maxv: number };
46	  const maxApplied = maxRow.maxv;
47	
48	  // RC-3: Forward-only guard. The database records a version for which no
49	  // migration file exists — a file was deleted or the wrong migrations
50	  // directory was used.
51	  if (maxApplied > maxFileVersion) {
52	    throw new Error(
53	      `schema regression: schema_migrations contains version ${maxApplied} but ` +
54	        `highest known migration file is version ${maxFileVersion}`,
55	    );
56	  }
57	
58	  const checkApplied = writer.prepare<[number]>(
59	    'SELECT version FROM schema_migrations WHERE version = ?',
60	  );
61	  const recordApplied = writer.prepare<[number, string]>(
62	    'INSERT INTO schema_migrations (version, applied_at) VALUES (?, ?)',
63	  );
64	
65	  for (const file of files) {
66	    const version = parseInt(file.slice(0, 4), 10);
67	
68	    if (checkApplied.get(version) !== undefined) continue;
69	
70	    // AC-3: Regression guard. A file exists that was not part of the
71	    // migration sequence when the database was last migrated — applying it
72	    // now would insert a version below what the database already has,
73	    // violating forward-only semantics.
74	    if (version < maxApplied) {
75	      throw new Error(
76	        `schema regression: migration file ${file} has version ${version} which is ` +
77	          `lower than highest applied version ${maxApplied}`,
78	      );
79	    }
80	
81	    const sql = fs.readFileSync(path.join(migrationsDir, file), 'utf-8');
82	    writer.transaction(() => {
83	      writer.exec(sql);
84	      recordApplied.run(version, new Date().toISOString());
85	    })();
86	  }
87	}
