  it('DEFAULT_RETRY_LADDER length equals DEFAULT_MAX_OUTER_RETRIES', () => {
    expect(DEFAULT_RETRY_LADDER.length).toBe(DEFAULT_MAX_OUTER_RETRIES);
  });
});

